/**
 * Nodal Analysis Studio - engine validation harness (NA1).
 *
 * Standalone gate runner modeled on tools/validation/welltest: labeled
 * CASES, per-check tolerances stated inline, exit 0 only on full pass.
 * Run from the repo root:
 *
 *   node tools/validation/nodal/run-validation.mjs
 *
 * Prerequisite: goldens generated by the independent Python oracle
 * (python3 tools/validation/nodal/genfixtures.py), committed at
 * src/utils/nodal/__tests__/goldens.json.
 *
 * CASE 1  Moody/Colebrook friction vs the oracle's bisection route
 *         (fixed-point vs bisection; < 0.2 % everywhere, laminar exact)
 * CASE 2  Numerics analytic truths (Brent root of cos x = x, exact
 *         linear fit recovery, interpolation identities)
 * CASE 3  Vogel dimensionless identity and calibration round trip
 *         (the equation itself is the anchor)
 * CASE 4  Oil IPR family vs oracle goldens (composite Standing continuity
 *         and below-pb calibration algebra, Fetkovich, Jones)
 * CASE 5  Black-oil PVT adapter vs oracle across a p, T matrix
 *         (Rs / Bo / muO / Z / Bg / muG / water / densities / sigma)
 * CASE 6  Minimum-curvature trajectory vs oracle + exact arc identities
 * CASE 7  Gas deliverability: JS trapezoid m(p) + Darcy IPR vs the
 *         oracle's Simpson quadrature route (<= 1 %), plus closed-form
 *         back-pressure / LIT identities
 * CASE 8  Published literature fixtures - armed only when book-verified
 *         data is present in literature-fixtures.json (repo precedent:
 *         gates arm only from owner-provided sources)
 */

import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

import { brentSolve, linearFit, linearInterp } from '../../../src/utils/nodal/numerics.js';
import { moodyFrictionFactor } from '../../../src/utils/nodal/friction.js';
import { buildFluidModel, pvtAt } from '../../../src/utils/nodal/pvt.js';
import { computeIpr, rateAtPwf } from '../../../src/utils/nodal/ipr.js';
import { buildTrajectory, tvdAtMd } from '../../../src/utils/nodal/trajectory.js';
import { darcyGasIpr, backPressureIpr, litIpr } from '../../../src/utils/nodal/iprGas.js';

const here = path.dirname(fileURLToPath(import.meta.url));
const goldens = JSON.parse(
  fs.readFileSync(path.join(here, '../../../src/utils/nodal/__tests__/goldens.json'), 'utf8')
);
const literature = JSON.parse(
  fs.readFileSync(path.join(here, 'literature-fixtures.json'), 'utf8')
);

let passed = 0;
let failed = 0;

const check = (name, actual, expected, relTol, unit = '') => {
  const err = Math.abs(actual - expected) / Math.max(Math.abs(expected), 1e-300);
  const ok = Number.isFinite(actual) && err <= relTol;
  const detail = `${actual}${unit ? ` ${unit}` : ''} vs ${expected}${unit ? ` ${unit}` : ''} (rel err ${err.toExponential(2)}, tol ${relTol})`;
  console.log(`  ${ok ? 'PASS' : 'FAIL'}  ${name}: ${detail}`);
  if (ok) passed += 1; else failed += 1;
};

const banner = (t) => console.log(`\n=== ${t} ===`);

// ---------------------------------------------------------------------------
banner('CASE 1: Moody/Colebrook friction vs oracle bisection route');
for (const c of goldens.friction) {
  const f = moodyFrictionFactor(c.re, c.relRough);
  check(`f(Re=${c.re}, rr=${c.relRough})`, f, c.f, 2e-3);
}

// ---------------------------------------------------------------------------
banner('CASE 2: numerics analytic truths');
{
  const dottie = brentSolve((x) => Math.cos(x) - x, 0, 1, { tol: 1e-14 });
  check('Brent root of cos x = x (Dottie number)', dottie.root, 0.7390851332151607, 1e-9);
  const fit = linearFit([1, 2, 3, 4, 5], [2.5, 4.5, 6.5, 8.5, 10.5]);
  check('linearFit slope on exact line', fit.slope, 2, 1e-12);
  check('linearFit intercept on exact line', fit.intercept, 0.5, 1e-12);
  check('linearInterp midpoint identity', linearInterp([0, 10], [100, 200], 5), 150, 1e-12);
}

// ---------------------------------------------------------------------------
banner('CASE 3: Vogel dimensionless identity + calibration round trip');
{
  const v = goldens.ipr.vogel;
  const ipr = computeIpr({ model: 'vogel', pr: v.pr, qmax: v.qmax });
  for (const p of v.points) {
    check(`Vogel q(pwf=${p.pwf})`, rateAtPwf(ipr, p.pwf), p.q, 1e-12, 'stb/d');
  }
  const cal = computeIpr({ model: 'vogel', pr: v.pr, testPoint: { q: 700, pwf: 1000 } });
  check('Vogel qmax calibrated from (700, 1000)', cal.qmax, 1000, 1e-9, 'stb/d');
}

// ---------------------------------------------------------------------------
banner('CASE 4: oil IPR family vs oracle goldens');
{
  const c = goldens.ipr.composite;
  const ipr = computeIpr({ model: 'composite', pr: c.pr, pb: c.pb, pi: c.pi });
  for (const p of c.points) {
    check(`composite q(pwf=${p.pwf})`, rateAtPwf(ipr, p.pwf), p.q, 1e-9, 'stb/d');
  }
  const qTest = rateAtPwf(ipr, 1500);
  const cal = computeIpr({ model: 'composite', pr: c.pr, pb: c.pb, testPoint: { q: qTest, pwf: 1500 } });
  check('composite J from below-pb test point', cal.pi, c.jFromTestBelowPb, 1e-9, 'stb/d/psi');

  const f = goldens.ipr.fetkovich;
  const fIpr = computeIpr({ model: 'fetkovich', pr: f.pr, c: f.c, n: f.n });
  for (const p of f.points) {
    check(`fetkovich q(pwf=${p.pwf})`, rateAtPwf(fIpr, p.pwf), p.q, 1e-9, 'stb/d');
  }

  const j = goldens.ipr.jones;
  const jIpr = computeIpr({ model: 'jones', pr: j.pr, a: j.a, b: j.b });
  for (const p of j.points) {
    check(`jones q(pwf=${p.pwf})`, rateAtPwf(jIpr, p.pwf), p.q, 1e-9, 'stb/d');
  }
}

// ---------------------------------------------------------------------------
banner('CASE 5: black-oil PVT adapter vs oracle across p, T matrix');
{
  const model = buildFluidModel({
    api: goldens.model.api,
    gasSg: goldens.model.gasSg,
    gor: goldens.model.gor,
    salinityPpm: goldens.model.salinityPpm,
  });
  for (const c of goldens.pvt) {
    const js = pvtAt(model, c.p, c.tF);
    const label = `p=${c.p} T=${c.tF}`;
    check(`${label} pb`, js.pb, c.props.pb, 2e-3, 'psia');
    check(`${label} rs`, js.rs, c.props.rs, 2e-3, 'scf/stb');
    check(`${label} bo`, js.bo, c.props.bo, 1e-3, 'rb/stb');
    check(`${label} muO`, js.muO, c.props.muO, 5e-3, 'cp');
    check(`${label} z`, js.z, c.props.z, 1e-9);
    check(`${label} muG`, js.muG, c.props.muG, 1e-9, 'cp');
    check(`${label} bw`, js.bw, c.props.bw, 1e-9, 'rb/stb');
    check(`${label} muW`, js.muW, c.props.muW, 1e-9, 'cp');
    check(`${label} rhoO`, js.rhoO, c.props.rhoO, 1e-3, 'lbm/ft3');
    check(`${label} rhoG`, js.rhoG, c.props.rhoG, 1e-9, 'lbm/ft3');
    check(`${label} rhoW`, js.rhoW, c.props.rhoW, 1e-9, 'lbm/ft3');
    check(`${label} sigmaOG`, js.sigmaOG, c.props.sigmaOG, 1e-9, 'dyn/cm');
    check(`${label} sigmaWG`, js.sigmaWG, c.props.sigmaWG, 1e-9, 'dyn/cm');
  }
}

// ---------------------------------------------------------------------------
banner('CASE 6: minimum-curvature trajectory vs oracle + exact arcs');
{
  const t = goldens.trajectory;
  const traj = buildTrajectory({ mode: 'deviated', survey: t.survey });
  t.survey.forEach((s, i) => {
    check(`TVD at md ${s.md}`, tvdAtMd(traj, s.md), t.tvds[i], 1e-9, 'ft');
  });
  const quarter = buildTrajectory({
    mode: 'deviated',
    survey: [{ md: 0, inc: 0, azi: 0 }, { md: 900, inc: 90, azi: 0 }],
  });
  check('quarter-circle arc TVD = 2 dMd / pi', quarter.tvdMax, (2 * 900) / Math.PI, 1e-9, 'ft');
  const vertical = buildTrajectory({ mode: 'vertical', depthFt: 8500 });
  check('vertical identity TVD', vertical.tvdMax, 8500, 1e-12, 'ft');
}

// ---------------------------------------------------------------------------
banner('CASE 7: gas deliverability vs oracle Simpson route + closed forms');
{
  const g = goldens.gasIpr;
  // nPoints 7 makes the JS pwf grid land exactly on the golden pwfs
  // (3000, 2500, ..., 0), so the comparison needs no interpolation.
  const js = darcyGasIpr({ ...g.base, nPoints: 7 });
  for (const p of g.points) {
    if (p.q <= 0) continue;
    const qJs = js.curve.find((pt) => Math.abs(pt.pwf - p.pwf) < 1e-6)?.q;
    check(`darcy gas q(pwf=${p.pwf})`, qJs, p.q, 1.5e-2, 'Mscf/d');
  }
  const bp = backPressureIpr({ pr: 3000, c: 2e-4, n: 0.85 });
  check('back-pressure AOF closed form', bp.aof, 2e-4 * Math.pow(3000 ** 2, 0.85), 1e-12, 'Mscf/d');
  const lit = litIpr({ pr: 3000, a: 0.05, b: 5e-6 });
  check('LIT AOF inverts its quadratic', 0.05 * lit.aof + 5e-6 * lit.aof * lit.aof, 3000 ** 2, 1e-9, 'psi2');
}

// ---------------------------------------------------------------------------
banner('CASE 8: published literature fixtures');
{
  const armed = (literature.fixtures || []).filter((f) => f.armed);
  if (armed.length === 0) {
    console.log('  SKIP  no armed literature fixtures yet; gates arm when book-verified data is committed');
  }
  for (const f of armed) {
    console.log(`  (armed fixture "${f.id}" has no runner yet - NA2+ wires it)`);
  }
}

// ---------------------------------------------------------------------------
console.log(`\n${failed === 0 ? 'ALL GATES PASS' : 'GATES FAILED'}: ${passed} passed, ${failed} failed`);
process.exit(failed === 0 ? 0 : 1);
